var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"후우. 아슬아슬했네.","JPN":"ふぅ、ギリギリだったわね。","ENG":"Whew, that was close.","TWN":"呼，好險。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"펴...... 평생 뛸 것 오늘 다 뛴 기분이야......","JPN":"い……一生分動いた気がする。","ENG":"I... I don't think I want to run ever again...","TWN":"感……感覺我這一輩子要跑的都跑完了……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그래서, 생존자는 우리 셋뿐이야?","JPN":"それで、生存者は私たち三人だけ？","ENG":"So, are the three of us the only survivors?","TWN":"所以，現在倖存者就只剩我們三個人了是嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"지금으로선 그래. 다른 애들은 전부 저기서 우릴 찾고 있잖아?","JPN":"現状はそうね。他の子たちはみんな、あそこで私たちを探してるみたいだし。","ENG":"For now, yes. The others are over there, looking for us.","TWN":"目前來說是的。其他人都在找我們呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"카운터들이 전부 손도 못 쓰고 당하다니...... 진짜 유령 아냐?","JPN":"カウンターたちが抵抗もできずにやられるなんて……本当に幽霊なんじゃない？","ENG":"These Counters went down without even knowing what hit them. What if it really is a ghost?","TWN":"制裁者居然這麼輕易就被控制了……難道真的是鬼幹的好事？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 카일 녀석 뒤통수를 리프노드로 후려쳐서라도 돌아가는 건데......","JPN":"こうなるとわかってたら、カイルのやつの後頭部をリーフノードで殴り飛ばして、帰れば良かった。","ENG":"I wish I knew better. I would have hit Kyle on the back of his head with Leaf Node if I had to drag him out of here.","TWN":"早知如此，哪怕用節點打死凱爾那個傢伙，也應該回去的……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아냐. 탄도 미사일을 발사시키겠다고 협박했으면......","JPN":"いや、弾道ミサイルを発射するって脅しておけば……","ENG":"Or I could just have threatened to launch a ballistic missile...","TWN":"不，應該威脅他說要發射彈道導彈的……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"방식이 조금 과격한 아이였구나. 무서워라.","JPN":"やり方が少し過激なのね。怖いわ。","ENG":"I didn't know you were so aggressive. Scary!","TWN":"妳這孩子有點過激啊，我好害怕。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"진정하세요, 실비아 씨.","JPN":"落ち着いてください、シルビアさん。","ENG":"Calm down, Sylvia.","TWN":"冷靜點，希爾維亞。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"유령 얘기로 혼란스러우신 건 알겠지만, 이럴 때일수록 침착해야 돼요.","JPN":"幽霊の話で混乱しているのはわかりますが、こういう時ほど冷静になる必要があります。","ENG":"I understand that this ghost story is confusing, but we shouldn't let it get to us, especially at a time like this.","TWN":"我知道鬼不鬼的讓妳感到很混亂，但越是這種時候就越要冷靜。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그, 그래. 무서운 건 아니고 정신이 없는 거지......","JPN":"わかったわよ。でも、怖いんじゃなくてちょっと落ち着かないだけ……","ENG":"O-okay. I'm not scared. I'm just not clear-headed...","TWN":"好，好。我不是怕，我只是亂……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"고립된 지역이라는 조건은 그대로잖아요. 생존자가 우리 셋이면 그 중 한 명은 범인이겠죠.","JPN":"孤立した地域という条件は変わっていません。生存者が私たち3人ならその中の誰かが犯人だということです。","ENG":"We're still stuck in this area. Since only the three of us are left, one of us has to be the culprit.","TWN":"這裡仍然是孤立的地區，就是說兇手就在我們三個倖存者當中。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"주시윤 녀석한테 붙어 있던 유령이 전자기 펄스에 떨어져 나갔을지도 모르잖아.","JPN":"アキヤマ・シリュウについてた幽霊が、電磁パルスでどっかに飛ばされた可能性だってあるでしょ。","ENG":"Maybe it really was a ghost and it was driven out of Shiyoon by my EMP.","TWN":"說不定在周時雲身上的鬼，因為電磁脈衝分離了呢？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그 점은 저도 사장님과 같은 생각이에요. 유령 같은 비과학적인 현상은 있을 수 없어요.","JPN":"それは私も社長と同じ考えです。幽霊のような非科学的な現象はあり得ません。","ENG":"I have to agree with the Boss on that. Paranormal phenomena like ghosts don't exist.","TWN":"我和老闆的想法一樣，這世上根本就不存在像鬼這樣的非科學現象。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아무리 말이 안 되는 것 같아도 차근차근 의심해가다 보면 해답에 다다를 수 있어요.","JPN":"いくらあり得ないように思えても、一つずつ疑っていけば答えに辿り着けます。","ENG":"No matter how mysterious this looks, we can solve it if we apply ourselves.","TWN":"即使多麼荒唐，只要仔細斟酌一番，就可以找到答案。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......좋아, 네 말대로 그럼 여기 있는 셋 중에 한 명이 범인이라고 쳐.","JPN":"……じゃあ、アンタの言うとおり、この三人のうち一人が犯人だとして。","ENG":"Okay, then let's say one of us is the perpetrator.","TWN":"……好，就像妳說的，兇手就在我們三個人當中。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그럼 제일 의심 가는 사람은 너 아냐? 남들 뒤통수 치는 게 네 특기잖아?","JPN":"一番怪しいのは、アンタじゃない？　人を裏切るのがアンタの特技だし。","ENG":"Then aren't you the most likely suspect? Since backstabbing is your expertise?","TWN":"那麼最可疑的不就是妳？妳的特長不就是背叛別人嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아하하. 어떻게 잘 아시네요. 부끄러운 특기라 이력서에는 안 적었는데.","JPN":"アハハ、よく知ってますね？　恥ずかしい特技なので履歴書には書いてないのに。","ENG":"Ah hah hah. How did you know? I didn't even mention it on my resume.","TWN":"啊哈哈，妳怎麼知道？那個特長讓我挺害羞的，所以都沒寫到履歷上。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"뭐, 부정하진 않을게요. 제가 범인일지도 모르죠.","JPN":"まぁ、否定はしませんよ。私が犯人かもしれません。","ENG":"Well, I won't deny that I may be the perpetrator.","TWN":"我並不否認，兇手有可能就是我。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"하지만 결론을 내리기 전에 몇 가지만 물어볼게요. 그 정도는 괜찮죠?","JPN":"でも、結論を出す前にいくつか質問があります。それくらいいいですよね？","ENG":"But before you make any decision, may I ask you a few questions?","TWN":"但下定論之前我可以問幾個問題吧？可以嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그야...... 질문 정도라면......","JPN":"まぁ……質問くらいなら……","ENG":"Well… sure…","TWN":"這個嘛……問個問題還是可以……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"알렉스 씨?","JPN":"アレックスさん？","ENG":"Alex.","TWN":"雅蕾克絲？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"메이드 분들은 정확히 어떻게 희생자가 된 거죠? 범인이 직접 등장했나요?","JPN":"メイドの方々は正確にはどのように犠牲になったのですか？　犯人が直接姿を現したんですか？","ENG":"How exactly did the maids fall victims? Did the perpetrator show up?","TWN":"準確來說，女僕們是怎麼成為受害者的？是兇手出現了嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"흐음. 희생자들을 제외하면 다른 사람은 나타나지 않았어.","JPN":"う～ん。犠牲者たち以外の人は現れなかったわ。","ENG":"Hm, there was no one else except for the victims.","TWN":"唔，除了受害者外並沒有出現其他人。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"전투 중에 제이크라는 사람이 몰래 뒤로 돌아와서 메이드 아가씨들을 쓰러뜨렸지, 아마?","JPN":"戦闘中にジェイクって人が後ろから襲ってきて、お嬢ちゃんたちを倒したの。","ENG":"But during the fight, this man named Jake went behind their backs and knocked them out, I think.","TWN":"戰鬥中，應該是一個叫傑克的人偷偷來到後方，擊敗女僕小姐們的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"그리고 다시 일어난 메이드 아가씨들은 둘 다 희생자가 되어 있었어.","JPN":"そして、起き上がったメイドのお嬢ちゃんたちは二人とも犠牲者になっていたわ。","ENG":"When they woke up, both of them had become victims.","TWN":"重新爬起來的女僕小姐們，就這麼成為了受害者。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 성야의 저주에는 전염 능력도 있다는 뜻이 되겠네요?","JPN":"そしたら、聖夜の呪いには伝染能力もあるということになりますね？","ENG":"So, the Curse of the Holy Night can be contagious.","TWN":"妳的意思是星夜的詛咒是可以傳染的？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GREATSWORD_XMAS_NULL_NULL","text":{"KOREA":"잘은 모르겠지만...... 그렇지 않으려나?","JPN":"よくはわからないけど……多分そうなのかしら？","ENG":"I don't know... Maybe.","TWN":"雖然我不是很清楚……應該有可能吧？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREATSWORD_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 실비아 씨.","JPN":"そしたら、シルビアさん。","ENG":"Now, Sylvia.","TWN":"希爾維亞。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"왜?","JPN":"なに？","ENG":"Yes?","TWN":"怎麼了？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제이크라는 분이 그 키 큰 군인이죠?","JPN":"ジェイクという人は、あの背の高い軍人さんですよね？","ENG":"This man, Jake. He's the tall soldier, right?","TWN":"傑克是不是一個高個子的軍人？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"맞아. 중요할 때 쓸모없으면서 항상 느끼한 말이나 해대는 버터맨이지.","JPN":"そうよ。いざって時に使えないくせに、気持ち悪いセリフをぶちかますバターマンよ。","ENG":"Right. He's a sleazeball who can't stop saying oily things but is useless when important.","TWN":"對，需要他的時候派不上用場，他就是個只會油嘴滑舌的油膩男。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......그렇군요. 이제 알겠어요.","JPN":"……そうですか。これでわかりました。","ENG":"Okay, I get it now.","TWN":"……原來如此，我現在知道了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"수수께끼는 모두 풀렸습니다!","JPN":"謎はすべて解けたのです。","ENG":"The mystery has been solved!","TWN":"所有的謎底都解開了！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};